export default function Sidebar(props) {
    const {userData}=props
    let name = ''
    if (userData) {
        console.log("user", userData)
        name = userData.first_name + ' ' + userData.sur_name

    } 

    return (
        <div >
            <li>Home</li>
            <li>Train information</li>
            <li>Contact Us</li>
            <li>Login</li>
        </div>
    )
}
